import { takaro, data } from '@takaro/helpers';

async function main() {
    const discordChannel = data.module.userConfig.discordChannelIdCustom;
    const serverStatus = data.eventData.status;

    if (serverStatus === 'online') {
        await takaro.discord.discordControllerSendMessage(discordChannel, {
            message: `🟢 **Server Online**`,
        });
    } else if (serverStatus === 'offline') {
        await takaro.discord.discordControllerSendMessage(discordChannel, {
            message: `🔴 **Server Offline**`,
        });
    }
}

await main();

import { data, takaro } from '@takaro/helpers';

async function main() {
    // Parse player name from log message
    const logMessage = data.eventData?.msg;
    if (!logMessage) {
        console.log('PlayerDied: No log message found in event data.');
        return;
    }

    // Extract player name from: "[PrismaCore]playerDied: Wyked (Steam_76561198118541500) died @ 2445 52 -353"
    const nameMatch = logMessage.match(/playerDied:\s+([^(]+)\s+\(/);
    if (!nameMatch || !nameMatch[1]) {
        console.log('PlayerDied: Could not parse player name from log message:', logMessage);
        return;
    }

    const playerName = nameMatch[1].trim();

    const discordChannel = data.module.userConfig.discordChannelIdCustom;
    await takaro.discord.discordControllerSendMessage(discordChannel, {
        message: `☠️ **${playerName}** *died*`,
    });
}

await main();

