import { takaro, data, axios } from '@takaro/helpers';

async function getSteamPersonaName(steamId, playerId, moduleId) {
    const cached = await takaro.variable.variableControllerSearch({
        filters: {
            key: ['steamPersonaName'],
            playerId: [playerId],
            moduleId: [moduleId],
        },
    });
    if (cached.data.data.length > 0 && cached.data.data[0].value) {
        return cached.data.data[0].value;
    }

    try {
        const res = await axios.get(`https://steamcommunity.com/profiles/${steamId}/?xml=1`, {
            timeout: 5000,
            responseType: 'text',
        });
        const match = String(res.data).match(/<steamID><!\[CDATA\[([^\]]+)\]\]><\/steamID>/);
        if (match && match[1]) {
            const personaName = match[1].trim();
            if (personaName) {
                await takaro.variable.variableControllerCreate({
                    key: 'steamPersonaName',
                    value: personaName,
                    playerId: playerId,
                    moduleId: moduleId,
                });
                return personaName;
            }
        }
    } catch (err) {
        console.error('Failed to fetch Steam persona name:', err.message);
    }
    return null;
}

async function main() {
    if (data.eventData.msg.startsWith('/')) return;
    if (data.eventData.msg.startsWith('!')) return;
    if (data.eventData.msg.startsWith('$')) return;
    if (!data.player) return;

    let sender = data.player.name;

    if (/^Survivor(\s*\(\d+\))?$/i.test(sender.trim()) && data.player.steamId) {
        const steamName = await getSteamPersonaName(
            data.player.steamId,
            data.player.id,
            data.module.moduleId,
        );
        if (steamName) sender = steamName;
    }

    const onlyGlobal = data.module.userConfig.onlyGlobalChat;
    if (onlyGlobal && data.eventData.channel !== 'global') return;

    const discordChannel = data.module.userConfig.discordChannelIdCustom;
    const message = `**${sender}**: ${data.eventData.msg}`;
    await takaro.discord.discordControllerSendMessage(discordChannel, {
        message: message,
    });
}

await main();

import { takaro, data } from '@takaro/helpers';

async function main() {
    const { player, gameServerId, module: mod } = data;
    const discordChannel = mod.userConfig.discordChannelIdCustom;
    const playtimeHours = Math.floor(player.playtimeSeconds / 3600);

    // Check if player has been seen before
    const seenCheck = await takaro.variable.variableControllerSearch({
        filters: {
            key: ['seenPlayer'],
            playerId: [player.id],
            moduleId: [data.module.moduleId]
        }
    });

    if (seenCheck.data.data.length === 0) {
        // New player - set variable and announce to Discord
        await takaro.variable.variableControllerCreate({
            key: 'seenPlayer',
            value: 'true',
            playerId: player.id,
            moduleId: data.module.moduleId
        });

        const newPlayerChannel = mod.userConfig.newPlayerDiscordChannel;
        if (newPlayerChannel) {
            const serverDetails = await takaro.gameserver.gameServerControllerGetOne(gameServerId);
            const serverName = serverDetails.data.data.name;

            const messageTemplate = mod.userConfig.newPlayerDiscordMessage || '🎆 **{player}** is a new player. Welcome to **{server}**!';
            const message = messageTemplate.replace('{player}', player.name).replace('{server}', serverName);

            await takaro.discord.discordControllerSendMessage(newPlayerChannel, {
                message: message,
            });
        }
    }

    await takaro.discord.discordControllerSendMessage(discordChannel, {
        message: `🎆 **${player.name}** connected \n       🎮 **Playtime:** ${playtimeHours} hours`,
    });
}

await main();

